    int u, v;
} Edge;

// Define the structure for a graph
typedef struct Graph {
    int n, m;
    Edge *edges;
} Graph;

// Function to find bridges in the graph
void findBridges(Graph *graph) {
    int *low = (int *)malloc(graph->n * sizeof(int));
    int *disc = (int *)malloc(graph->n * sizeof(int));
    int *parent = (int *)malloc(graph->n * sizeof(int));
    int *visited = (int *)malloc(graph->n * sizeof(int));
    int time = 0;
    int bridgeCount = 0;

    // Initialize the arrays
    for (int i = 0; i < graph->n; i++) {
        low[i] = -1;
        disc[i] = -1;
        parent[i] = -1;
        visited[i] = 0;
    }

    // Perform DFS to find bridges
    for (int i = 0; i < graph->n; i++) {
        if (!visited[i]) {
            dfs(graph, i, low, disc, parent, visited, &time, &bridgeCount);
        }
    }

    // Print the number of pairs of bridges
    printf("%d\n", bridgeCount * (bridgeCount - 1) / 2);
}

// Function to perform DFS
void dfs(Graph *graph, int u, int *low, int *disc, int *parent, int *visited, int *time, int *bridgeCount) {
    visited[u] = 1;
    disc[u] = *time;
    low[u] = *time;
    (*time)++;

    // Iterate over all edges connected to u
    for (int i = 0; i < graph->m; i++) {
        int v = (graph->edges[i].u == u) ? graph->edges[i].v : graph->edges[i].u;
        if (!visited[v]) {
            parent[v] = u;
            dfs(graph, v, low, disc, parent, visited, time, bridgeCount);
            low[u] = (low[u] < low[v]) ? low[u] : low[v];
            if (low[v] > disc[u]) {
                (*bridgeCount)++;
            }
        } else if (v != parent[u]) {
            low[u] = (low[u] < disc[v]) ? low[u] : disc[v];
        }
    }
}

int main() {
    int t;
    scanf("%d", &t);

    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);

        Graph graph;
        graph.n = n;
        graph.m = m;
