void findBridges(Graph &graph) {
    vector<int> low(graph.n, -1);
    vector<int> disc(graph.n, -1);
    vector<int> parent(graph.n, -1);
    vector<bool> visited(graph.n, false);
    int time = 0;
    int bridgeCount = 0;

    // Perform DFS to find bridges
    for (int i = 0; i < graph.n; i++) {
        if (!visited[i]) {
            dfs(graph, i, low, disc, parent, visited, time, bridgeCount);
        }
    }

    // Print the number of pairs of bridges
    cout << bridgeCount * (bridgeCount - 1) / 2 << endl;
}

// Function to perform DFS
void dfs(Graph &graph, int u, vector<int> &low, vector<int> &disc, vector<int> &parent, vector<bool> &visited, int &time, int &bridgeCount) {
    visited[u] = true;
    disc[u] = time;
    low[u] = time;
    time++;

    // Iterate over all edges connected to u
    for (const auto &edge : graph.edges) {
        int v = (edge.u == u) ? edge.v : edge.u;
        if (!visited[v]) {
            parent[v] = u;
            dfs(graph, v, low, disc, parent, visited, time, bridgeCount);
            low[u] = min(low[u], low[v]);
            if (low[v] > disc[u]) {
                bridgeCount++;
            }
        } else if (v != parent[u]) {
            low[u] = min(low[u], disc[v]);
        }
    }
